def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio == 1:
            val = 0
            for a in range(1, 5):
                for b in range(1, 4):
                    val += ((-1)**(a+b)) * (ratio ** (a*b)) / (a+b)
            priorities[i] = abs(val) * 20
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                for l in range(1, 4):
                    penalty += ((ratio ** (3 * k + l)))/((k + l) * 3)
            priorities[i] = ratio ** 4 + penalty
            if ratio > 2:
                boost = 0
                for m in range(1, 6):
                    boost += (ratio ** (-m)) * (m ** 0.5)
                priorities[i] += boost * 5
        elif 0 < ratio < 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j**0.5)
                score += term
            if ratio < 0.2:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 15
            elif ratio < 0.75:
                multiplier = 10
            else:
                multiplier = 5
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio < 1:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1)**m) * (ratio ** (m+1)) / (m + 2)
                priorities[i] += abs(extra) * 3
            if ratio > 0.9:
                sum_exp = 0
                for n in range(1, 4):
                    sum_exp += np.exp(-ratio * n) * n
                priorities[i] -= sum_exp
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    return priorities
